# workers/tasks/llm.py
from celery import Task
from celery.exceptions import SoftTimeLimitExceeded
from anthropic import Anthropic, APIStatusError
from workers.celery_app import celery_app
from db import update_job_status, write_job_result

client = Anthropic()

class LLMBaseTask(Task):
    """Base class so the Anthropic client is shared across task calls."""
    abstract = True
    _client: Anthropic | None = None

    @property
    def client(self) -> Anthropic:
        if self._client is None:
            self._client = Anthropic()
        return self._client

@celery_app.task(
    base=LLMBaseTask,
    bind=True,
    name="tasks.summarise",
    queue="llm",
    max_retries=3,
    acks_late=True,
)
def summarise(self, job_id: str, user_id: str, text: str, model: str) -> dict:
    update_job_status(job_id, "running", attempt=self.request.retries + 1)
    try:
        response = self.client.messages.create(
            model=model,
            max_tokens=1024,
            messages=[{"role": "user", "content": f"Summarise concisely:\n\n{text}"}],
        )
        result = {
            "summary": response.content[0].text,
            "input_tokens": response.usage.input_tokens,
            "output_tokens": response.usage.output_tokens,
        }
        write_job_result(job_id, result)
        return result

    except SoftTimeLimitExceeded:
        update_job_status(job_id, "failed", error="Task exceeded time limit")
        raise  # let Celery handle the hard kill

    except APIStatusError as exc:
        if exc.status_code in (429, 529):
            delay = 30 * (2 ** self.request.retries)
            raise self.retry(exc=exc, countdown=delay)
        update_job_status(job_id, "failed", error=str(exc))
        raise

    except Exception as exc:
        if self.request.retries < self.max_retries:
            raise self.retry(exc=exc, countdown=30)
        update_job_status(job_id, "dead", error=str(exc))
        raise

