from celery.signals import task_prerun, task_postrun, task_failure, task_retry
import logging, time

logger = logging.getLogger("celery.tasks")

@task_prerun.connect
def task_started(task_id, task, args, kwargs, **_):
    logger.info("task_start", extra={"task": task.name, "task_id": task_id})
    task._start_ts = time.monotonic()

@task_postrun.connect
def task_finished(task_id, task, args, kwargs, retval, state, **_):
    elapsed = time.monotonic() - getattr(task, "_start_ts", time.monotonic())
    logger.info("task_end",
                extra={"task": task.name, "task_id": task_id,
                       "state": state, "elapsed_s": round(elapsed, 2)})

@task_failure.connect
def task_errored(task_id, exception, traceback, sender, **_):
    logger.error("task_failure",
                 extra={"task": sender.name, "task_id": task_id,
                        "error": str(exception)},
                 exc_info=exception)

@task_retry.connect
def task_retrying(request, reason, **_):
    logger.warning("task_retry",
                   extra={"task": request.task, "task_id": request.id,
                          "attempt": request.retries, "reason": str(reason)})
